#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

// Constants for IoT System
#define DEVICE_ID "SENSOR_001"
#define TEMP_THRESHOLD 30.0
#define MAX_BUFFER_SIZE 100

// Data structure for sensor reading
typedef struct {
 char device_id[20];
 float temperature;
 float humidity;
 char timestamp[30];
} SensorData;

// Data structure for message packet
typedef struct {
 char topic[50];
 char payload[200];
 int qos;
} MessagePacket;

// ============================================
// BLOCK 1: Device and Sensing Functions
// ============================================

float read_temperature_sensor() {
 // Simulate reading from a temperature sensor (25-35°C range)
 return 25.0 + (rand() % 100) / 10.0;
}

float read_humidity_sensor() {
 // Simulate reading from humidity sensor (40-60% range)
 return 40.0 + (rand() % 200) / 10.0;
}

SensorData sense_environment() {
 SensorData data;
 strcpy(data.device_id, DEVICE_ID);
 data.temperature = read_temperature_sensor();
 data.humidity = read_humidity_sensor();

 time_t now = time(NULL);
 strcpy(data.timestamp, ctime(&now));
 data.timestamp[strlen(data.timestamp) - 1] = '\0'; // Remove newline

 printf("[SENSING] Read: Temp=%.1f°C, Humidity=%.1f%%\n", 
 data.temperature, data.humidity);
 return data;
}

// ============================================
// BLOCK 2: Communication Functions
// ============================================

MessagePacket format_mqtt_message(SensorData *data) {
 MessagePacket msg;

 // Format as JSON-like string (simplified)
 sprintf(msg.topic, "iot/%s/data", data->device_id);
 sprintf(msg.payload, "{\"temp\":%.1f,\"humidity\":%.1f,\"time\":\"%s\"}",
 data->temperature, data->humidity, data->timestamp);
 msg.qos = 1;

 return msg;
}

int send_to_gateway(MessagePacket *msg) {
 // Simulate sending to gateway (80% success rate for demo)
 int success = (rand() % 100) < 80;

 if (success) {
 printf("[COMMUNICATION] Sent to gateway:\n");
 printf(" Topic: %s\n", msg->topic);
 printf(" Payload: %s\n", msg->payload);
 } else {
 printf("[COMMUNICATION] Failed to send to gateway\n");
 }
 return success;
}

// ============================================
// BLOCK 3: Data Processing Functions
// ============================================

void process_data(SensorData *data, int *alert_triggered) {
 *alert_triggered = 0;

 // Business logic: Check temperature threshold
 if (data->temperature > TEMP_THRESHOLD) {
 *alert_triggered = 1;
 printf("[PROCESSING] ⚠ ALERT: Temperature exceeds threshold!\n");
 }

 // Store to database (simulated)
 printf("[PROCESSING] Data stored in time-series database\n");
}

// ============================================
// BLOCK 4: Application Interface Functions
// ============================================

void update_dashboard(SensorData *data, int alert) {
 printf("[APPLICATION] Dashboard updated\n");
 printf(" Device: %s\n", data->device_id);
 printf(" Temperature: %.1f°C\n", data->temperature);
 printf(" Status: %s\n", alert ? "⚠ ALERT" : "✓ Normal");
}

void send_notification(int alert, SensorData *data) {
 if (alert) {
 printf("[APPLICATION] 📱 Notification sent: High temperature alert!\n");
 }
}

// ============================================
// Main IoT System Execution
// ============================================

int main() {
 srand(time(NULL)); // Initialize random seed

 printf("=== IoT Device Simulation ===\n\n");

 // Run simulation for 5 iterations
 for (int i = 0; i < 5; i++) {
 printf("\n--- Iteration %d ---\n", i + 1);

 // Block 1: Sense
 SensorData sensor_data = sense_environment();

 // Block 2: Communicate
 MessagePacket message = format_mqtt_message(&sensor_data);
 int sent = send_to_gateway(&message);

 // If failed, buffer locally (simulated)
 if (!sent) {
 printf("[COMMUNICATION] Message buffered for retry\n");
 }

 // Block 3: Process
 int alert_triggered;
 process_data(&sensor_data, &alert_triggered);

 // Block 4: Application Interface
 update_dashboard(&sensor_data, alert_triggered);
 send_notification(alert_triggered, &sensor_data);

 // Simulate time delay
 printf("\n");
 }

 printf("=== Simulation Complete ===\n");
 return 0;
}
